(function () {
  const mocks = [
    {
      id: 'sbi-po-short-20',
      name: 'SBI PO ג€” Short Mock (20 Questions)',
      template: 'ssc',
      examCatalogueId: 'sbi-po',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 15,
      marking: { correct: 1, wrong: -0.25, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'en', name: 'English Language', questions: [
          { id: 'sbi-po-s20-1', text: 'Read the sentence and choose the option that best completes the inference. "Despite repeated warnings about the storm, the captain pressed on, and within hours the vessel was struggling against waves it could not survive." The passage most strongly implies that the captain\'s decision was:', options: ['well-judged and cautious', 'reckless and ill-advised', 'forced by his superiors', 'praised by the crew'], correct: 1, topic: 'Reading', difficulty: 'easy-medium', explanation: 'The captain ignored repeated warnings and the vessel could not survive, so the decision is portrayed as reckless and ill-advised. The other options contradict the negative outcome described.' },
          { id: 'sbi-po-s20-2', text: 'Select the option that fills both blanks appropriately: "The new policy was designed to ____ small businesses, but in practice it ____ them with extra paperwork." ', options: ['burden / relieved', 'support / burdened', 'ignore / helped', 'tax / rewarded'], correct: 1, topic: 'Cloze', difficulty: 'medium', explanation: 'The contrast marker "but in practice" requires opposite ideas: an intended benefit (support) that became a hindrance (burdened). "support / burdened" gives this contrast logically.' },
          { id: 'sbi-po-s20-3', text: 'Identify the part that contains a grammatical error: "Neither the manager nor the employees (A)/ was aware (B)/ of the sudden change (C)/ in the schedule. (D)"', options: ['A', 'B', 'C', 'D'], correct: 1, topic: 'Error Detection', difficulty: 'medium', explanation: 'With "neither...nor", the verb agrees with the nearer subject "employees" (plural), so "was" must be "were". The error is in part B.' },
          { id: 'sbi-po-s20-4', text: 'Choose the best improvement for the underlined part: "If he would have studied harder, he would have passed the examination."', options: ['would have studied', 'had studied', 'has studied', 'No improvement'], correct: 1, topic: 'Sentence Improvement', difficulty: 'medium-hard', explanation: 'In a third conditional, the "if" clause takes the past perfect: "If he had studied harder, he would have passed." So "had studied" is correct.' },
          { id: 'sbi-po-s20-5', text: 'Arrange to form a coherent paragraph. P: It quickly became the most downloaded app of the year. Q: A small team launched a simple note-taking application. R: Encouraged, they added cloud syncing and sharing features. S: Users loved its clean design and speed.', options: ['Q S R P', 'Q S P R', 'S Q R P', 'Q R S P'], correct: 0, topic: 'Para-jumble', difficulty: 'hard', explanation: 'Q introduces the app, S explains why users loved it, R shows the team responding to that love by adding features, and P concludes with its success. The order Q-S-R-P is logically coherent.' },
          { id: 'sbi-po-s20-6', text: 'Select the word most nearly OPPOSITE in meaning to "PRUDENT".', options: ['Cautious', 'Wise', 'Reckless', 'Thrifty'], correct: 2, topic: 'Vocabulary', difficulty: 'easy', explanation: 'Prudent means careful and sensible. Its antonym is "reckless". Cautious, wise and thrifty are near-synonyms of prudent.' },
        ]},
        { id: 'qa', name: 'Quantitative Aptitude', questions: [
          { id: 'sbi-po-s20-7', text: 'Simplify: 15% of 480 + 25% of 320 גˆ’ 40', options: ['100', '108', '112', '120'], correct: 2, topic: 'Simplification', difficulty: 'easy', explanation: '15% of 480 = 72; 25% of 320 = 80; 72 + 80 = 152; 152 גˆ’ 40 = 112.' },
          { id: 'sbi-po-s20-8', text: 'Find the next term in the series: 7, 9, 13, 21, 37, ?', options: ['61', '65', '69', '73'], correct: 2, topic: 'Number Series', difficulty: 'medium', explanation: 'Differences double: +2, +4, +8, +16, then +32. So 37 + 32 = 69.' },
          { id: 'sbi-po-s20-9', text: 'A sum becomes ג‚¹6050 in 2 years and ג‚¹6655 in 3 years at compound interest. The rate of interest per annum is:', options: ['8%', '10%', '12%', '15%'], correct: 1, topic: 'Interest', difficulty: 'medium-hard', explanation: 'Interest in the 3rd year = 6655 גˆ’ 6050 = 605, earned on the amount 6050. Rate = 605/6050 ֳ— 100 = 10%.' },
          { id: 'sbi-po-s20-10', text: 'A man sells two articles at ג‚¹990 each. On one he gains 10% and on the other he loses 10%. His overall result is:', options: ['no profit no loss', 'loss of ג‚¹20', 'gain of ג‚¹20', 'loss of ג‚¹100'], correct: 1, topic: 'Profit and Loss', difficulty: 'medium', explanation: 'CP of gain item = 990/1.10 = 900; CP of loss item = 990/0.90 = 1100. Total CP = 2000, total SP = 1980. Loss = ג‚¹20.' },
          { id: 'sbi-po-s20-11', text: 'Two pipes A and B can fill a tank in 12 and 18 minutes respectively. If both are opened together, the tank fills in:', options: ['6.8 min', '7.0 min', '7.2 min', '7.5 min'], correct: 2, topic: 'Time and Work', difficulty: 'medium-hard', explanation: 'Combined rate = 1/12 + 1/18 = (3 + 2)/36 = 5/36 per minute. Time = 36/5 = 7.2 minutes.' },
          { id: 'sbi-po-s20-12', text: 'In a class of 50 students, 60% are boys. If the average weight of boys is 55 kg and of girls is 45 kg, the average weight of the class is:', options: ['49 kg', '50 kg', '51 kg', '52 kg'], correct: 2, topic: 'Average', difficulty: 'easy-medium', explanation: 'Boys = 30, girls = 20. Total weight = 30ֳ—55 + 20ֳ—45 = 1650 + 900 = 2550. Average = 2550/50 = 51 kg.' },
          { id: 'sbi-po-s20-13', text: 'A bar chart shows monthly profit (in ג‚¹ lakh): Jan 10, Feb 18, Mar 14, Apr 22. By what percent did April profit exceed the average of the four months?', options: ['25%', '30%', '37.5%', '40%'], correct: 2, topic: 'Data Interpretation', difficulty: 'hard', explanation: 'Total = 10+18+14+22 = 64; average = 64/4 = 16. April = 22; excess = 22 גˆ’ 16 = 6. Percent = 6/16 ֳ— 100 = 37.5%.' },
        ]},
        { id: 'ra', name: 'Reasoning Ability', questions: [
          { id: 'sbi-po-s20-14', text: 'In a row of people facing north, P is 7th from the left and Q is 5th from the right. If there are 3 people between P and Q, and P is to the left of Q, how many people are in the row?', options: ['12', '14', '15', '16'], correct: 2, topic: 'Ranking', difficulty: 'medium', explanation: 'P is 7th from the left. With 3 people between P and Q, Q is at position 7 + 3 + 1 = 11 from the left. Q is 5th from the right, so total = 11 + 5 גˆ’ 1 = 15.' },
          { id: 'sbi-po-s20-15', text: 'Statements: All pens are caps. Some caps are boxes. Conclusions: I. Some pens are boxes. II. Some caps are pens. Which conclusion(s) follow?', options: ['Only I', 'Only II', 'Both I and II', 'Neither I nor II'], correct: 1, topic: 'Syllogism', difficulty: 'medium', explanation: 'All pens are caps means some caps are pens (conversion), so II follows. "Some caps are boxes" gives no definite link between pens and boxes, so I does not follow. Only II follows.' },
          { id: 'sbi-po-s20-16', text: 'If P > Q = R ג‰¥ S > T, which of the following is definitely true?', options: ['P > T', 'Q < S', 'P = R', 'T ג‰¥ Q'], correct: 0, topic: 'Inequalities', difficulty: 'easy-medium', explanation: 'P > Q = R ג‰¥ S > T means P is greater than everything down the chain, so P > T is definitely true. The others either reverse or equate values not guaranteed.' },
          { id: 'sbi-po-s20-17', text: 'In a code, "MANGO" is written as "NBOHP". How is "APPLE" written in the same code?', options: ['BQQMF', 'BQQNF', 'BPQMF', 'CQQMF'], correct: 0, topic: 'Coding-Decoding', difficulty: 'medium-hard', explanation: 'Each letter shifts +1: Mג†’N, Aג†’B, Nג†’O, Gג†’H, Oג†’P. Applying +1 to APPLE: Aג†’B, Pג†’Q, Pג†’Q, Lג†’M, Eג†’F gives BQQMF.' },
          { id: 'sbi-po-s20-18', text: 'A is the brother of B. B is the daughter of C. D is the father of C. How is A related to D?', options: ['Son', 'Grandson', 'Nephew', 'Father'], correct: 1, topic: 'Blood Relations', difficulty: 'medium', explanation: 'B is daughter of C, and A is B\'s brother, so A is also C\'s child. D is the father of C, so D is A\'s grandfather, making A the grandson of D.' },
          { id: 'sbi-po-s20-19', text: 'A man walks 5 km North, turns right and walks 3 km, then turns right and walks 5 km. How far and in which direction is he from the start?', options: ['3 km East', '3 km West', '8 km East', '5 km South'], correct: 0, topic: 'Direction Sense', difficulty: 'easy', explanation: 'North 5, then East 3, then South 5 cancels the northward 5, leaving him 3 km East of the start.' },
          { id: 'sbi-po-s20-20', text: 'Data sufficiency: What is the age of the youngest of three brothers? Statement I: The average age of the three is 24 years. Statement II: The eldest is 30 and the middle is 24.', options: ['I alone is sufficient', 'II alone is sufficient', 'Both together are needed', 'Either alone is sufficient'], correct: 2, topic: 'Data Sufficiency', difficulty: 'hard', explanation: 'I alone gives only the total (3 ֳ— 24 = 72). II alone gives only the eldest and middle (30 and 24). Combining: youngest = 72 גˆ’ 30 גˆ’ 24 = 18. Both statements together are needed.' },
        ]},
      ],
    },
    {
      id: 'sbi-po-short-25',
      name: 'SBI PO ג€” Short Mock (25 Questions)',
      template: 'ssc',
      examCatalogueId: 'sbi-po',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 20,
      marking: { correct: 1, wrong: -0.25, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'en', name: 'English Language', questions: [
          { id: 'sbi-po-s25-1', text: 'Read and infer: "The committee adopted the proposal without a single dissenting voice, and members lingered afterward to congratulate its author." The passage suggests the proposal was:', options: ['controversial and divisive', 'unanimously well received', 'rejected outright', 'postponed for review'], correct: 1, topic: 'Reading', difficulty: 'easy', explanation: 'No dissent plus congratulations indicates unanimous approval and goodwill, so "unanimously well received" is correct.' },
          { id: 'sbi-po-s25-2', text: 'Choose the option that best fills both blanks: "The scientist remained ____ about the results until the data could be ____ by an independent lab."', options: ['certain / ignored', 'cautious / verified', 'careless / praised', 'hopeful / discarded'], correct: 1, topic: 'Cloze', difficulty: 'medium', explanation: 'A scientist awaiting independent confirmation would stay "cautious", and data would be "verified". Only this pair is internally consistent.' },
          { id: 'sbi-po-s25-3', text: 'Find the segment with an error: "One of the most important factor (A)/ that affect productivity (B)/ is the morale (C)/ of the employees. (D)"', options: ['A', 'B', 'C', 'D'], correct: 0, topic: 'Error Detection', difficulty: 'medium', explanation: '"One of the most important factors" requires the plural noun "factors". Segment A wrongly uses singular "factor".' },
          { id: 'sbi-po-s25-4', text: 'Choose the best improvement: "Hardly had I reached the station when the train left."', options: ['than the train left', 'when the train had left', 'then the train left', 'No improvement'], correct: 3, topic: 'Sentence Improvement', difficulty: 'medium-hard', explanation: '"Hardly...when" is the correct correlative pair with the past perfect in the first clause. The sentence is already correct, so no improvement is needed.' },
          { id: 'sbi-po-s25-5', text: 'Rearrange into a coherent paragraph. P: As a result, river levels rose dangerously. Q: Heavy monsoon rains battered the region for a week. R: Authorities ordered an immediate evacuation. S: Low-lying neighbourhoods began to flood.', options: ['Q P S R', 'Q S P R', 'S Q P R', 'Q P R S'], correct: 0, topic: 'Para-jumble', difficulty: 'hard', explanation: 'Q (rains) causes P (rivers rose), which causes S (flooding), prompting R (evacuation). The cause-effect order Q-P-S-R is coherent.' },
          { id: 'sbi-po-s25-6', text: 'Select the word most nearly SIMILAR in meaning to "MITIGATE".', options: ['Intensify', 'Alleviate', 'Conceal', 'Postpone'], correct: 1, topic: 'Vocabulary', difficulty: 'easy-medium', explanation: 'Mitigate means to make less severe. "Alleviate" is its synonym. "Intensify" is the opposite.' },
          { id: 'sbi-po-s25-7', text: 'Identify the error: "The number of applications received this year (A)/ are higher (B)/ than the number received (C)/ last year. (D)"', options: ['A', 'B', 'C', 'D'], correct: 1, topic: 'Error Detection', difficulty: 'medium', explanation: '"The number of..." takes a singular verb, so "are higher" should be "is higher". The error is in segment B.' },
          { id: 'sbi-po-s25-8', text: 'Choose the option that best fills the blank: "The veteran journalist was known for her ____ questions that exposed evasive politicians."', options: ['trivial', 'incisive', 'rambling', 'apologetic'], correct: 1, topic: 'Vocabulary', difficulty: 'medium-hard', explanation: 'Questions that "exposed evasive politicians" must be sharp and penetrating, i.e., "incisive". The other options contradict that effect.' },
        ]},
        { id: 'qa', name: 'Quantitative Aptitude', questions: [
          { id: 'sbi-po-s25-9', text: 'Simplify: (36 ֳ· 4 + 5) ֳ— 3 גˆ’ 12', options: ['30', '33', '36', '42'], correct: 0, topic: 'Simplification', difficulty: 'easy', explanation: '36 ֳ· 4 = 9; 9 + 5 = 14; 14 ֳ— 3 = 42; 42 גˆ’ 12 = 30.' },
          { id: 'sbi-po-s25-10', text: 'Find the wrong term in the series: 4, 9, 19, 39, 80, 159', options: ['9', '19', '39', '80'], correct: 3, topic: 'Number Series', difficulty: 'medium', explanation: 'Pattern is ֳ—2+1: 4ג†’9ג†’19ג†’39ג†’79ג†’159. The term 80 should be 79, so 80 is the wrong term.' },
          { id: 'sbi-po-s25-11', text: 'Compare the roots: I. xֲ² גˆ’ 7x + 12 = 0  II. yֲ² גˆ’ 9y + 20 = 0. Which relation always holds?', options: ['x > y', 'x < y', 'x ג‰₪ y', 'relationship cannot be established'], correct: 2, topic: 'Quadratic Comparison', difficulty: 'medium-hard', explanation: 'Roots of I: x = 3, 4. Roots of II: y = 4, 5. Comparing all pairs, every x is less than or equal to every y (max x = 4 = min y), so x ג‰₪ y.' },
          { id: 'sbi-po-s25-12', text: 'The ratio of two numbers is 3 : 5 and their sum is 96. The smaller number is:', options: ['30', '36', '40', '60'], correct: 1, topic: 'Ratio', difficulty: 'easy-medium', explanation: 'Total parts = 3 + 5 = 8; one part = 96/8 = 12. Smaller number = 3 ֳ— 12 = 36.' },
          { id: 'sbi-po-s25-13', text: 'A trader buys goods for ג‚¹2400 and marks them 30% above cost. He gives a 10% discount. His profit is:', options: ['ג‚¹312', 'ג‚¹360', 'ג‚¹408', 'ג‚¹480'], correct: 2, topic: 'Profit and Loss', difficulty: 'medium', explanation: 'Marked price = 2400 ֳ— 1.30 = 3120; SP after 10% discount = 3120 ֳ— 0.90 = 2808; profit = 2808 גˆ’ 2400 = ג‚¹408.' },
          { id: 'sbi-po-s25-14', text: 'A train 180 m long crosses a platform 270 m long in 18 seconds. Its speed is:', options: ['72 km/h', '80 km/h', '90 km/h', '96 km/h'], correct: 2, topic: 'Speed', difficulty: 'medium-hard', explanation: 'Distance = 180 + 270 = 450 m in 18 s, so speed = 450/18 = 25 m/s = 25 ֳ— 18/5 = 90 km/h.' },
          { id: 'sbi-po-s25-15', text: 'A sum of ג‚¹8000 is invested at 12% simple interest per annum. The interest after 3 years is:', options: ['ג‚¹2400', 'ג‚¹2880', 'ג‚¹3200', 'ג‚¹3600'], correct: 1, topic: 'Interest', difficulty: 'easy', explanation: 'SI = Pֳ—Rֳ—T/100 = 8000 ֳ— 12 ֳ— 3 / 100 = 2880. The interest is ג‚¹2880.' },
          { id: 'sbi-po-s25-16', text: 'A pie chart of a family budget shows Rent 35%, Food 25%, Savings 15%, and the rest as Others. If total income is ג‚¹40000, the amount spent on Others is:', options: ['ג‚¹8000', 'ג‚¹9000', 'ג‚¹10000', 'ג‚¹12000'], correct: 2, topic: 'Data Interpretation', difficulty: 'medium', explanation: 'Others = 100% גˆ’ (35 + 25 + 15)% = 25%. Amount = 25% of 40000 = ג‚¹10000.' },
          { id: 'sbi-po-s25-17', text: 'A and B together can finish a job in 10 days. A alone can do it in 15 days. In how many days can B alone finish it?', options: ['20', '25', '30', '35'], correct: 2, topic: 'Time and Work', difficulty: 'hard', explanation: 'B\'s rate = 1/10 גˆ’ 1/15 = (3 גˆ’ 2)/30 = 1/30 per day. So B alone takes 30 days.' },
        ]},
        { id: 'ra', name: 'Reasoning Ability', questions: [
          { id: 'sbi-po-s25-18', text: 'Six friends sit in a row facing north. R is at one end. S is third to the right of R. T is immediately left of S. Which position is T from the left end?', options: ['2nd', '3rd', '4th', '5th'], correct: 1, topic: 'Seating Arrangement', difficulty: 'medium', explanation: 'R at position 1; S third to the right of R is position 4; T immediately left of S is position 3. So T is 3rd from the left.' },
          { id: 'sbi-po-s25-19', text: 'Statements: All dogs are animals. No animal is a plant. Conclusions: I. No dog is a plant. II. Some animals are dogs. Which conclusion(s) follow?', options: ['Only I', 'Only II', 'Both I and II', 'Neither I nor II'], correct: 2, topic: 'Syllogism', difficulty: 'medium-hard', explanation: 'All dogs are animals and no animal is a plant, so no dog is a plant (I follows). Since all dogs are animals, some animals are dogs by conversion (II follows). Hence both follow.' },
          { id: 'sbi-po-s25-20', text: 'Which symbol replaces the blank to make both true: P ג‰¥ Q ___ R, given P ג‰¥ R is definitely true?', options: ['Q < R', 'Q > R', 'Q = R', 'Q ג‰¥ R'], correct: 3, topic: 'Inequalities', difficulty: 'medium', explanation: 'For P ג‰¥ R to be guaranteed, Q must be at least R so the chain holds: P ג‰¥ Q ג‰¥ R gives P ג‰¥ R. "Q ג‰¥ R" makes it definite.' },
          { id: 'sbi-po-s25-21', text: 'If "GARDEN" is coded as "HBSEFO", how is "FLOWER" coded?', options: ['GMPXFS', 'GMPYFS', 'GNPXFS', 'GMQXFS'], correct: 0, topic: 'Coding-Decoding', difficulty: 'medium-hard', explanation: 'Each letter shifts +1. Fג†’G, Lג†’M, Oג†’P, Wג†’X, Eג†’F, Rג†’S gives GMPXFS.' },
          { id: 'sbi-po-s25-22', text: 'Pointing to a photograph, Reena said, "She is the only daughter of my mother\'s mother." Who is in the photograph relative to Reena?', options: ['Mother', 'Aunt', 'Grandmother', 'Sister'], correct: 0, topic: 'Blood Relations', difficulty: 'easy-medium', explanation: 'The only daughter of Reena\'s maternal grandmother is Reena\'s mother (assuming the mother is that only daughter). So the photograph is of Reena\'s mother.' },
          { id: 'sbi-po-s25-23', text: 'A person starts facing East, turns 90ֲ° clockwise, then 180ֲ°, then 90ֲ° anticlockwise. Which direction does he now face?', options: ['North', 'South', 'East', 'West'], correct: 3, topic: 'Direction Sense', difficulty: 'easy', explanation: 'East + 90ֲ° clockwise = South; +180ֲ° = North; +90ֲ° anticlockwise from North = West. He now faces West.' },
          { id: 'sbi-po-s25-24', text: 'Data sufficiency: Is M the tallest among M, N and O? Statement I: M is taller than N. Statement II: O is shorter than N.', options: ['I alone sufficient', 'II alone sufficient', 'Both together sufficient', 'Neither sufficient'], correct: 2, topic: 'Data Sufficiency', difficulty: 'hard', explanation: 'I gives M > N only. II gives O < N only. Together: M > N and N > O imply M > N > O, so M is tallest. Both statements together are sufficient.' },
          { id: 'sbi-po-s25-25', text: 'In a certain code, 5 means "+", 3 means "גˆ’", 7 means "ֳ—". What is the value of "6 7 4 3 5 5 2" interpreted as 6 ֳ— 4 גˆ’ 5 + 2?', options: ['19', '20', '21', '23'], correct: 2, topic: 'Coding-Decoding', difficulty: 'medium', explanation: 'Substitute symbols: 6 ֳ— 4 גˆ’ 5 + 2 = 24 גˆ’ 5 + 2 = 21.' },
        ]},
      ],
    },
  ];
  window.EXAMS = (window.EXAMS || []).concat(mocks);
})();
